var _ IPermissionManager = (*permissionManagerStubWrapper)(nil)

// NewPermissionManagerStub creates a server-side IPermissionManager wrapping the given
// server implementation. The returned value satisfies IPermissionManager
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewPermissionManagerStub(
	impl IPermissionManagerServer,
) IPermissionManager {
	wrapper := &permissionManagerStubWrapper{impl: impl}
	stub := &PermissionManagerStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
